#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
struct Seg{int l,r,sum;};
const int N=1e6+10,M=2e6+10;;
int buf[N],*dp[N],*cur=buf,dep[N],res[N],mxs[N];
struct Graph
{
	int head[N],des[M],nxt[M],cnt;
	inline void ins(int x,int y){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;}
}a;
inline void dfs1(int u,int fa=0)
{
	grep(a,u,i)
	{
		int v=a.des[i];if(v==fa)continue;
		dfs1(v,u);dep[v]>dep[mxs[u]]?mxs[u]=v:0;
	}
	dep[u]=dep[mxs[u]]+1;
}
inline void dfs2(int u,int fa=0)
{
	dp[u][0]=1;if(mxs[u])
	{
		dp[mxs[u]]=dp[u]+1;
		dfs2(mxs[u],u);res[u]=res[mxs[u]]+1;
	}
	grep(a,u,i)
	{
		int v=a.des[i];if(v==mxs[u]||v==fa)continue;
		dp[v]=cur;cur+=dep[v];dfs2(v,u);
		rep(1,dep[v],i)
		{
			dp[u][i]+=dp[v][i-1];
			if(dp[u][i]>dp[u][res[u]]||(dp[u][i]==dp[u][res[u]]&&(i<res[u])))res[u]=i;
		}
	}
	if(dp[u][res[u]]==1)res[u]=0;
}
int main()
{
	int n=read();rep(2,n,i){int x=read(),y=read();a.ins(x,y);a.ins(y,x);}
	dfs1(1);dp[1]=cur;cur+=dep[1];dfs2(1);rep(1,n,i)printf("%d\n",res[i]);return 0;
}
